sql:
SELECT ship_name, average_rating
FROM cruise_ships
WHERE max_guests >= 5000;

SELECT cruise_line, AVG(ship_length) AS average_length
FROM cruise_ships
GROUP BY cruise_line;

SELECT COUNT(cabin_number) AS number_of_cabins
FROM cabins
WHERE ship_id = 1;

SELECT cc.category_name, cp.price_per_person, cp.discount_rate, cp.dynamic_pricing_factor
FROM cabin_categories cc
INNER JOIN cabin_prices cp ON cc.category_id = cp.category_id;

SELECT AVG(cabin_size) 
FROM cabin_categories 
WHERE category_name = 'Main Deck Triple' AND min_guests = 2;

SELECT ship_name 
FROM cruise_ships 
WHERE average_rating = (
    SELECT MAX(average_rating) 
    FROM cruise_ships
);

SELECT first_name, last_name, email, phone, role, ship_id, date_hired, date_terminated, position_duration, performance_rating, training_certifications
FROM cruise_staff
WHERE performance_rating > 4.0;

SELECT total_cabins
FROM cruise_ships
WHERE ship_id = 1;

SELECT cruise_line, SUM(max_guests) AS total_guests
FROM cruise_ships
GROUP BY cruise_line;

external_knowledge:
- 'floating domiciles' refers to the cabins on the cruise ship;
- 'travelers' refers to the guests;
- 'voyage of the majestic ship number 2' refers to the cruise ship with ship_id = 2;
- 'boarding tokens' refers to booking IDs;
- 'idyllic retreats where they will be anchoring' refers to the cabins where they have booked a stay.

sql:
SELECT agent_id, COUNT(*) AS total_bookings
FROM agent_bookings
GROUP BY agent_id;

SELECT COUNT(cabin_id) 
FROM availability 
WHERE status = 'Available' AND booked_by IS NULL;

external_knowledge:
- "Majestic vessels" refers to cruise ships; 
- "Spacious abodes" refers to cabin categories; 
- "Capable of welcoming at least a quartet of travelers" means the cabin can accommodate at least four guests; 
- "Rates not exceeding a thousand golden coins per head" means the price per person is $1000 or less.

sql:
SELECT * 
FROM cabins 
WHERE cabin_rating = 5.0;

SELECT ship_name, total_cabins
FROM cruise_ships
ORDER BY total_cabins DESC;

SELECT activity_name, description, date_and_time, location, activity_type
FROM cruise_activities
WHERE ship_id = 1;

SELECT ship_name, average_rating 
FROM cruise_ships
ORDER BY average_rating DESC;

external_knowledge:
- 'More affordable' refers to cabins with a price per person above 6000, which is considered an economic option due to possible discounts or promotions;
- 'Smaller cabins' means those that can accommodate fewer than 7 guests;
- 'Open for booking' indicates the cabin status is 'Available'.
